
"""Runtime configuration for automated ML backend service."""

from __future__ import annotations

from dataclasses import dataclass
from functools import lru_cache
import os


_ALLOWED_ENVIRONMENTS = {"development", "staging", "production", "test"}
_ALLOWED_LOG_LEVELS = {"CRITICAL", "ERROR", "WARNING", "INFO", "DEBUG"}


# Generated by GitHub Copilot
def _parse_bool(value: str | None, *, default: bool) -> bool:
    """Parse environment boolean values with a deterministic fallback."""

    if value is None:
        return default
    normalized = value.strip().lower()
    if normalized in {"1", "true", "yes", "y", "on"}:
        return True
    if normalized in {"0", "false", "no", "n", "off"}:
        return False
    return default


# Generated by GitHub Copilot
def _parse_int(value: str | None, *, default: int, minimum: int) -> int:
    """Parse environment integer values while enforcing lower bounds."""

    try:
        parsed = int(value) if value is not None else default
    except (TypeError, ValueError):
        return default
    return parsed if parsed >= minimum else default


@dataclass(frozen=True)
class Settings:
    """Represents backend configuration loaded from environment variables."""

    app_env: str
    app_name: str
    app_version: str
    db_path: str
    cors_origins: list[str]
    summary_size: int
    drift_confidence_threshold: float
    rate_limit_per_minute: int
    api_key: str
    enforce_api_key: bool
    max_request_body_bytes: int
    log_level: str


@lru_cache(maxsize=1)
def get_settings() -> Settings:
    """Load settings from environment variables with safe defaults."""

    app_env = os.getenv("MLOPS_ENV", "development").strip().lower()
    if app_env not in _ALLOWED_ENVIRONMENTS:
        app_env = "development"

    app_name = os.getenv("MLOPS_APP_NAME", "automated-ml-prediction-annotation-system")
    app_version = os.getenv("MLOPS_APP_VERSION", "0.2.0")
    db_path = os.getenv("MLOPS_DB_PATH", "./data/automl_assistant.db")

    origin_value = os.getenv(
        "MLOPS_CORS_ORIGINS",
        "http://127.0.0.1:4173,http://localhost:4173",
    )
    cors_origins = [origin.strip() for origin in origin_value.split(",") if origin.strip()]

    summary_size = int(os.getenv("MLOPS_SUMMARY_SIZE", "100"))
    drift_confidence_threshold = float(os.getenv("MLOPS_DRIFT_THRESHOLD", "0.55"))
    rate_limit_per_minute = int(os.getenv("MLOPS_RATE_LIMIT_PER_MINUTE", "600"))
    api_key = os.getenv("MLOPS_API_KEY", "").strip()
    enforce_api_key = _parse_bool(
        os.getenv("MLOPS_ENFORCE_API_KEY"),
        default=app_env == "production",
    )
    max_request_body_bytes = _parse_int(
        os.getenv("MLOPS_MAX_REQUEST_BODY_BYTES"),
        default=1_048_576,
        minimum=1_024,
    )
    log_level = os.getenv("MLOPS_LOG_LEVEL", "INFO").strip().upper()
    if log_level not in _ALLOWED_LOG_LEVELS:
        log_level = "INFO"

    return Settings(
        app_env=app_env,
        app_name=app_name,
        app_version=app_version,
        db_path=db_path,
        cors_origins=cors_origins,
        summary_size=summary_size,
        drift_confidence_threshold=drift_confidence_threshold,
        rate_limit_per_minute=rate_limit_per_minute,
        api_key=api_key,
        enforce_api_key=enforce_api_key,
        max_request_body_bytes=max_request_body_bytes,
        log_level=log_level,
    )
